(function(){try{var saved=localStorage.getItem('azure-move-lang');var nav=(navigator.language||'en');var supported=['en','pt-BR','zh-CN','es','fr','ar','ru','ja'];var lang=saved||(supported.indexOf(nav)!==-1?nav:(nav.indexOf('pt')===0?'pt-BR':nav.split('-')[0]));if(supported.indexOf(lang)===-1)lang='en';document.documentElement.lang=lang;document.documentElement.dir=(lang==='ar')?'rtl':'ltr';}catch(e){}})();